export interface DelegationScope {
  /**
   * Impact levels this delegation covers. The delegate may only exercise authority for cases at these impact levels.
   */
  impactLevels?: ('rights-impacting' | 'safety-impacting' | 'operational' | 'informational')[];
  /**
   * Case types this delegation covers. The delegate may only exercise authority for cases of these types.
   */
  caseTypes?: string[];
  /**
   * Maximum dollar value for determinations under this delegation.
   */
  maxDollarThreshold?: number;
  /**
   * FEL expression (Runtime Companion §8.2) that further narrows when the delegation applies. Evaluated against the evaluation context; the delegation is active only when this expression evaluates to true. Same FEL evaluation contract as `DueProcess.scope`, `ReviewProtocolBinding.scope`, and `HoldPolicy.scope`.
   */
  conditions?: string;
}
export interface HoldPolicy {
  /**
   * Reason for the hold. MUST be one of the seven standard values OR an `x-` prefixed vendor extension. Standard values: `pending-applicant-response`, `pending-external-verification`, `pending-legal-review`, `pending-legislation`, `pending-related-case`, `voluntary-hold`, `legal-hold`. Vendor extensions MUST match `^x-[a-z][a-z0-9-]*$` (e.g., `x-acme-pending-tribal-review`). Note: `legal-hold` has distinct semantics per S7.15 -- it has no event-based `resumeTrigger`, survives terminal workflow states, and blocks data destruction/retention expiry regardless of ordinary workflow state; `resumeTrigger` and `timeoutAction` are NOT required when `holdType` is `legal-hold`.
   */
  holdType: (
    | (
        | 'pending-applicant-response'
        | 'pending-external-verification'
        | 'pending-legal-review'
        | 'pending-legislation'
        | 'pending-related-case'
        | 'voluntary-hold'
        | 'legal-hold'
      )
    | {
        [k: string]: unknown;
      }
  ) &
    string;
  /**
   * Expected ISO 8601 duration of this hold, or the literal string 'indefinite' for holds with no expected end time. When the duration expires without the resumeTrigger firing, the processor applies the timeoutAction. As a WOS extension, the `P<N>BD` form denotes N business days resolved against an attached Business Calendar sidecar.
   */
  expectedDuration: string;
  /**
   * Event name that resumes the case from this hold. The processor listens for this event and resumes the case when it fires — this is NOT a FEL condition polled on a schedule (Governance S12.1).
   */
  resumeTrigger?: string;
  /**
   * Action when expectedDuration expires without the resume trigger (Governance S12.2). 'escalate': route to supervisor. 'auto-resume': resume the case automatically. 'cancel': cancel the case.
   */
  timeoutAction?: 'escalate' | 'auto-resume' | 'cancel';
  /**
   * Notification template key for hold notifications. When present, the processor sends a notification using this template when the hold begins.
   */
  notificationTemplateKey?: string;
  /**
   * FEL expression that determines when this hold policy applies (Runtime Companion S8.2). Evaluated against the evaluation context. When absent, the policy applies to all holds of the declared holdType.
   */
  scope?: string;
  /**
   * Human-readable description of this hold policy and its regulatory or procedural basis. Used in tooling and audit documentation.
   */
  description?: string;
}
